 /**
 * Example 31.1
 *
 * (c) Stephen Fryatt, 2026
 *
 * File: results.h
 */

#ifndef EXAMPLEAPP_RESULTS
#define EXAMPLEAPP_RESULTS

/* Results Initialisation. */

void results_initialise(void);

/* Open the Window. */

void results_open(void);

#endif

/* Initialise the program modules. */

calc_initialise();
ibar_initialise(main_application_sprite);
win_initialise(sprites);
results_initialise();

/* Mouse Click event handler */

static void ibar_mouse_click(wimp_pointer *pointer)
{
	switch (pointer->buttons) {
	case wimp_CLICK_SELECT:
		win_open();
		break;
	case wimp_CLICK_ADJUST:
		results_open();
		break;
	}
}

/* Results Menu Entries. */

#define RESULTS_MENU_CLEAR 0

/* Global Variables. */

static wimp_w results_handle = NULL;
static wimp_menu *results_menu = NULL;

/* Function Prototypes. */

static void results_menu_selection(wimp_w window, wimp_menu *menu, wimp_selection *selection);

/* Results Window Initialisation. */

void results_initialise(void)
{
	os_error		*error;
	wimp_window		*window_definition;

	/* Load and create the window. */

	window_definition = windows_load_template("Results");
	if (window_definition == NULL) {
		error_msgs_report_error("BadResultsTempl");
		return;
	}

	results_handle = wimp_create_window(window_definition);
	free(results_handle);

	/* Window Menu. */

	results_menu = menu_create("ResultsMenu", 1);
	if (results_menu == NULL) {
		error_msgs_report_error("BadResultsMenu");
		return;
	}

	menu_entry(results_menu, RESULTS_MENU_CLEAR, "ResultsMenu0", NULL);

	/* Register event handlers. */

	event_add_window_menu(results_handle, results_menu);
	event_add_window_menu_selection(results_handle, results_menu_selection);
}

/* Menu Selection event handler. */

static void results_menu_selection(wimp_w window, wimp_menu *menu, wimp_selection *selection)
{
	os_error *error;

	if (menu != results_menu)
		return;

	switch (selection->items[0]) {
	case RESULTS_MENU_CLEAR:
		break;
	}
}

/* Open the Window. */

void results_open(void)
{
	windows_open_centred_on_screen(results_handle);
}

/* Results Window Icons. */
#define RESULTS_TITLE_ICONS 6
#define RESULTS_ICON_TITLE_SHAPE 0 #define RESULTS_ICON_TITLE_SIDES 1 #define RESULTS_ICON_TITLE_ANGLES 2 #define RESULTS_ICON_TITLE_LENGTH 3 #define RESULTS_ICON_TITLE_PERIMETER 4 #define RESULTS_ICON_TITLE_AREA 5 #define RESULTS_ICON_ROW_SHAPE 6 #define RESULTS_ICON_ROW_SIDES 7 #define RESULTS_ICON_ROW_ANGLES 8 #define RESULTS_ICON_ROW_LENGTH 9 #define RESULTS_ICON_ROW_PERIMETER 10 #define RESULTS_ICON_ROW_AREA 11

/* Results Window Initialisation. */

void results_initialise(void)
{
	os_error		*error;
	wimp_window		*window_definition;

	/* Load and create the window. */

	window_definition = windows_load_template("Results");
	if (window_definition == NULL) {
		error_msgs_report_error("BadResultsTempl");
		return;
	}

	window_definition->icon_count = RESULTS_TITLE_ICONS;

	results_icons = window_definition->icons;

	results_handle = wimp_create_window(window_definition);

	/* Window Menu. */

	results_menu = menu_create("ResultsMenu", 1);
	if (results_menu == NULL) {
		error_msgs_report_error("BadResultsMenu");
		return;
	}

	menu_entry(results_menu, RESULTS_MENU_CLEAR, "ResultsMenu0", NULL);

	/* Register event handlers. */

	event_add_window_menu(results_handle, results_menu);
	event_add_window_menu_selection(results_handle, results_menu_selection);
}

struct wimp_draw
{
	wimp_w	w;
	os_box	box;
	int	xscroll;
	int	yscroll;
	os_box	clip;
};

typedef struct wimp_draw wimp_draw;

extern osbool wimp_redraw_window(
	wimp_draw *redraw
);

extern osbool wimp_get_rectangle(
	wimp_draw *draw
);

static void results_redraw(wimp_draw *redraw)
{
	osbool more;

	more = wimp_redraw_window(redraw);

	while (more) {
		/* We could do some redrawing here... */

		more = wimp_get_rectangle(redraw);
	}
}

/* Register event handlers. */

event_add_window_redraw_event(results_handle, results_redraw);
event_add_window_menu(results_handle, results_menu);
event_add_window_menu_selection(results_handle, results_menu_selection);

osbool more;

more = wimp_redraw_window(redraw);

while (more) {
	/* We could do some redrawing here... */

	more = wimp_get_rectangle(redraw);
}
